use base64::Engine;
use solana_pubkey::Pubkey;
use solana_vote_interface::state::{VoteStateV3, VoteStateV4};
use std::str::FromStr;

fn main() {
    let pubkey = Pubkey::from_str("7tKWFaaLi2FJSqukHxUrnXph8M3ynrqn3kEkKPpgcNHZ").unwrap();

    let base64_data = "";

    let raw_data = base64::engine::general_purpose::STANDARD
        .decode(base64_data)
        .unwrap();

    println!("Data length: {} bytes", raw_data.len());
    println!(
        "Version discriminant: {}",
        u32::from_le_bytes(raw_data[0..4].try_into().unwrap())
    );
    println!();

    // Attempt 1: VoteStateV3::deserialize (only handles discriminants 0, 1, 2)
    match VoteStateV3::deserialize(&raw_data) {
        Ok(v3) => {
            println!("VoteStateV3::deserialize succeeded!");
            println!("  node_pubkey: {}", v3.node_pubkey);
            println!("  commission: {}", v3.commission);
            println!("  epoch_credits count: {}", v3.epoch_credits.len());
            if let Some(last) = v3.epoch_credits.last() {
                println!("  latest epoch: {}", last.0);
            }
        }
        Err(e) => {
            println!("VoteStateV3::deserialize FAILED: {:?}", e);
        }
    }

    println!();

    // Attempt 2: VoteStateV4::deserialize (handles discriminants 0, 1, 2, 3)
    match VoteStateV4::deserialize(&raw_data, &pubkey) {
        Ok(v4) => {
            println!("VoteStateV4::deserialize succeeded!");
            println!("  node_pubkey: {}", v4.node_pubkey);
            println!(
                "  inflation_rewards_commission_bps: {}",
                v4.inflation_rewards_commission_bps
            );
            println!(
                "  block_revenue_commission_bps: {}",
                v4.block_revenue_commission_bps
            );
            println!("  bls_pubkey_compressed: {:?}", v4.bls_pubkey_compressed);
            println!("  epoch_credits count: {}", v4.epoch_credits.len());
            if let Some(last) = v4.epoch_credits.last() {
                println!("  latest epoch: {}", last.0);
            }
        }
        Err(e) => {
            println!("VoteStateV4::deserialize FAILED: {:?}", e);
        }
    }
}
